      <div style={{maxWidth:1100,margin:'0 auto',padding:'1rem 1rem'}}>

        {/* ── Single unified header strip: greeting + controls + tabs ── */}
        <div style={{background:darkMode?'#1e293b':'white',borderRadius:12,border:`1px solid ${darkMode?'#334155':'#e5e7eb'}`,marginBottom:'1rem',overflow:'hidden'}}>

          {/* Top row: greeting / blood group / dark+lang toggles / SOS */}
          <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',padding:'0.5rem 1rem',borderBottom:`1px solid ${darkMode?'#334155':'#f3f4f6'}`,gap:8,flexWrap:'wrap'}}>
            <div style={{display:'flex',alignItems:'center',gap:8,minWidth:0}}>
              <div style={{width:30,height:30,borderRadius:'50%',background:'linear-gradient(135deg,#052e16,#16a34a)',display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0}}>
                <span style={{color:'white',fontWeight:700,fontSize:'0.78rem'}}>{(user?.name||'U')[0].toUpperCase()}</span>
              </div>
              <div style={{minWidth:0}}>
                <div style={{fontSize:'0.85rem',fontWeight:700,color:darkMode?'#f1f5f9':'#111827',whiteSpace:'nowrap',overflow:'hidden',textOverflow:'ellipsis'}}>
                  {t('hello')}, <strong>{user?.name?.split(' ')[0]}</strong>
                </div>
                <div style={{fontSize:'0.62rem',color:'#6b7280',whiteSpace:'nowrap'}}>{t('dashboard_title')}</div>
              </div>
            </div>
            <div style={{display:'flex',gap:5,alignItems:'center',flexShrink:0,flexWrap:'wrap'}}>
              {user?.blood_group && (
                <span style={{background:'#fef2f2',color:'#dc2626',border:'1px solid #fca5a5',borderRadius:7,padding:'3px 7px',fontSize:'0.68rem',fontWeight:700,display:'flex',alignItems:'center',gap:3}}>
                  <I c="fa-droplet"/>{user.blood_group}
                </span>
              )}
              <button onClick={()=>setDarkMode(!darkMode)} title={t('dark_mode')}
                style={{background:darkMode?'#374151':'#f3f4f6',border:`1px solid ${darkMode?'#4b5563':'#e5e7eb'}`,borderRadius:7,padding:'4px 8px',cursor:'pointer',color:darkMode?'#f9fafb':'#374151',fontSize:'0.78rem'}}>
                <I c={darkMode?'fa-sun':'fa-moon'}/>
              </button>
              <button onClick={()=>{ const nl=lang==='en'?'sw':'en'; setLang(nl); i18nInstance.changeLanguage(nl); }} title={t('language')}
                style={{background:darkMode?'#374151':'#f3f4f6',border:`1px solid ${darkMode?'#4b5563':'#e5e7eb'}`,borderRadius:7,padding:'3px 8px',cursor:'pointer',color:darkMode?'#f9fafb':'#374151',fontSize:'0.68rem',fontWeight:700,display:'flex',alignItems:'center',gap:3}}>
                <I c="fa-language"/>{lang.toUpperCase()}
              </button>
              <button onClick={()=>setShowSOS(true)} className="btn btn-sm"
                style={{background:'#dc2626',color:'white',border:'none',animation:'sosPulse 2s ease-in-out infinite',padding:'4px 9px',fontSize:'0.75rem'}}>
                <I c="fa-circle-exclamation" style={{marginRight:3}}/>SOS
              </button>
            </div>
          </div>

          {/* Tab bar — sits flush inside the card, no outer margin */}
          <div className="tabs mh-tabs-wrap" style={{overflowX:'auto',WebkitOverflowScrolling:'touch',margin:0,borderBottom:'none',padding:'0 0.5rem'}}>
            {TABS.map(tab_info => (
              <button key={tab_info.key} className={`tab ${tab===tab_info.key?'active':''}`} onClick={()=>setTab(tab_info.key)}
                title={t(tab_info.labelKey)} style={{padding:'0.5rem 0.85rem',fontSize:'0.8rem'}}>
                <I c={tab_info.icon} style={{marginRight:4}}/><span className="mh-tab-label-long">{t(tab_info.labelKey)}</span>
              </button>
            ))}
          </div>
        </div>

                {tab==='chat'         && <Chatbot user={user} lang={lang}/>}
        {tab==='history'      && <History lang={lang}/>}
        {tab==='appointments' && <AppointmentsTab/>}
        {tab==='medications'  && <MedicationsTab/>}
        {tab==='trends'       && <HealthTrends/>}
        {tab==='hospitals'    && <HospitalMap/>}
        {tab==='profile'      && <Profile/>}

        {showSOS && <SOSModal onClose={()=>setShowSOS(false)} user={user}/>}
      </div>
      <style>{`
        @keyframes sosPulse { 0%,100%{box-shadow:0 0 0 0 rgba(220,38,38,0.4)} 50%{box-shadow:0 0 0 8px rgba(220,38,38,0)} }
      `}</style>
    </div>
  );
}
